// 定义圆周率常量
const PI: real := 3.14159265358979323846

// 方法：计算圆的周长
method CircleCircumference(radius: real) returns (circumference: real)
  requires radius >= 0.0
  ensures circumference == 2.0 * PI * radius
{
  circumference := 2.0 * PI * radius;
}
